from dataclasses import dataclass

@dataclass
class Triple:
    subject: str
    predicate: str
    object: str

# EVOLVE-BLOCK-START

def predict(triples: list[Triple]) -> str:
    """
    Convert a list of triples about a monument (or related entity) into a single
    fluent sentence. All triples are combined; each predicate is expressed with a
    suitable phrase.
    """
    if not triples:
        return ""

    from collections import defaultdict

    # Group triples by subject to handle different entities properly
    triples_by_subject = defaultdict(list)
    for triple in triples:
        triples_by_subject[triple.subject].append(triple)

    # Find the primary subject (monument) - look for monument-related keywords
    primary_subject = None
    for s in triples_by_subject.keys():
        if 'Monument' in s or 'Memorial' in s or 'Battlefield' in s:
            primary_subject = s
            break

    if primary_subject is None:
        # Prefer the subject with the most triples as primary
        primary_subject = max(triples_by_subject.keys(), key=lambda s: len(triples_by_subject[s]))

    other_subjects = [s for s in triples_by_subject.keys() if s != primary_subject]

    # Build the main sentence parts
    parts = [primary_subject]

    # Collect all monument predicates
    monument_predicates = []
    for triple in triples_by_subject[primary_subject]:
        p = triple.predicate
        o = triple.object.strip('"')
        monument_predicates.append((p, o))

    # Collect related entity predicates
    entity_predicates = defaultdict(list)
    for subject in other_subjects:
        for triple in triples_by_subject[subject]:
            p = triple.predicate
            o = triple.object.strip('"')
            entity_predicates[subject].append((p, o))

    # Build the main clause with monument information - prioritize key information
    main_clauses = []

    # Categorize predicates by importance for sentence flow
    location_info = []
    temporal_info = []
    descriptive_info = []
    other_info = []

    for p, o in monument_predicates:
        if p in ("location", "country", "state", "municipality", "district"):
            location_info.append((p, o))
        elif p in ("established", "foundingDate", "inaugurationDate"):
            temporal_info.append((p, o))
        elif p in ("category", "material", "designer", "dedicatedTo", "owner", "owningOrganisation", "nativeName"):
            descriptive_info.append((p, o))
        else:
            other_info.append((p, o))

    # Build clauses in logical order
    for p, o in location_info:
        if p == "category":
            main_clauses.append(f"is a {o}")
        elif p == "country":
            main_clauses.append(f"is located in {o}")
        elif p == "location":
            main_clauses.append(f"is located in {o}")
        elif p == "municipality":
            main_clauses.append(f"within the municipality of {o}")
        elif p == "state":
            main_clauses.append(f"in the state of {o}")
        elif p == "district":
            main_clauses.append(f"within the district of {o}")

    for p, o in temporal_info:
        if p in ("established", "foundingDate"):
            main_clauses.append(f"was established in {o}")
        elif p == "inaugurationDate":
            main_clauses.append(f"was inaugurated in {o}")

    for p, o in descriptive_info:
        if p == "owner" or p == "owningOrganisation":
            main_clauses.append(f"is owned by {o}")
        elif p == "dedicatedTo":
            main_clauses.append(f"is dedicated to {o}")
        elif p == "designer":
            main_clauses.append(f"was designed by {o}")
        elif p == "material":
            main_clauses.append(f"is made of {o}")
        elif p == "nativeName":
            main_clauses.append(f'known natively as {o}')

    for p, o in other_info:
        if p == "leader":
            main_clauses.append(f"has leader {o}")
        elif p == "leaderTitle":
            main_clauses.append(f"the leader title is {o}")
        elif p == "capital":
            main_clauses.append(f"the capital is {o}")
        elif p == "largestCity":
            main_clauses.append(f"the largest city is {o}")
        elif p == "currency":
            main_clauses.append(f"the currency is {o}")
        elif p == "language":
            main_clauses.append(f"the language spoken is {o}")
        elif p == "religion":
            main_clauses.append(f"the religion is {o}")
        elif p == "ethnicGroup":
            main_clauses.append(f"the ethnic group is {o}")
        elif p == "nearestCity":
            main_clauses.append(f"the nearest city is {o}")
        elif p == "legislature":
            main_clauses.append(f"the legislature is {o}")
        else:
            main_clauses.append(f"{p} is {o}")

    if main_clauses:
        parts.append(" " + ", ".join(main_clauses))

    # Add related entity information with relative clauses
    for subject in other_subjects:
        for p, o in entity_predicates[subject]:
            if p == "capital":
                parts.append(f", where the capital is {o}")
            elif p == "largestCity":
                parts.append(f", where the largest city is {o}")
            elif p == "country":
                parts.append(f", which is in {o}")
            elif p == "location":
                parts.append(f", located in {o}")
            elif p == "state":
                parts.append(f", in the state of {o}")
            elif p == "municipality":
                parts.append(f", in the municipality of {o}")
            elif p == "district":
                parts.append(f", part of the district of {o}")
            elif p == "hasToItsNorth":
                parts.append(f", with {o} to its north")
            elif p == "hasToItsSouthwest":
                parts.append(f", with {o} to its southwest")
            elif p == "hasToItsWest":
                parts.append(f", with {o} to its west")
            elif p == "hasToItsSoutheast":
                parts.append(f", with {o} to its southeast")
            else:
                parts.append(f", where {p} is {o}")

    sentence = "".join(parts) + "."
    return sentence.strip()

